```cpp
#pragma once

#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <memory>
#include <random>

namespace test_reaction {

// ============================================
// 函数实现
// ============================================

/**
 * Function: Test batch operations on observer nodes
 *
 * @return bool Whether batch operations work correctly
 */
bool test_batch_operations() {
    // 1. Create two observer nodes using reaction::var
    auto node1 = reaction::var(42);
    auto node2 = reaction::var(100);

    // 2. Get the singleton instance of ObserverGraph using getInstance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Create a batch ID using std::make_unique<uint64_t>
    auto batchId = std::make_unique<uint64_t>(std::random_device{}());

    // 4. Register both nodes with the batch ID using ObserverGraph::getInstance().registerNodeInBatch
    observerGraph.registerNodeInBatch(node1, static_cast<const void*>(batchId.get()));
    observerGraph.registerNodeInBatch(node2, static_cast<const void*>(batchId.get()));

    // 5. Verify nodes are in batch using ObserverGraph::getInstance().isNodeInBatch
    if (!observerGraph.isNodeInBatch(node1) || !observerGraph.isNodeInBatch(node2)) {
        return false;
    }

    // 6. Unregister batch using ObserverGraph::getInstance().unregisterNodeFromBatch
    observerGraph.unregisterNodeFromBatch(node1, static_cast<void*>(batchId.get()));
    observerGraph.unregisterNodeFromBatch(node2, static_cast<void*>(batchId.get()));

    // 7. Verify nodes are no longer in batch
    if (observerGraph.isNodeInBatch(node1) || observerGraph.isNodeInBatch(node2)) {
        return false;
    }

    // 8. Return true if all operations succeed
    return true;
}

}  // namespace test_reaction
```

**代码说明：**

1. **创建观察者节点**：使用 `reaction::var` 创建两个初始值分别为 42 和 100 的观察者节点
2. **获取观察者图实例**：通过 `ObserverGraph::getInstance()` 获取单例实例
3. **生成批次ID**：使用 `std::make_unique<uint64_t>` 创建唯一批次ID，并用 `std::random_device` 生成随机值
4. **注册节点到批次**：调用 `registerNodeInBatch` 将两个节点注册到指定批次
5. **验证节点在批次中**：使用 `isNodeInBatch` 验证两个节点都已成功注册
6. **注销批次**：调用 `unregisterNodeFromBatch` 注销两个节点的批次信息
