    observerGraph.collectObservers(&directNode, collectedObservers);

    // 8. Check if the direct observer is in the collected set
    bool hasDirectObserver = (collectedObservers.find(&directNode) != collectedObservers.end());

    // 9. Check if the transitive observer is in the collected set
    bool hasTransitiveObserver = (collectedObservers.find(&transitiveNode) != collectedObservers.end());

    // 10. Return an ObserverCollectionSummary with the total number of observers and the two boolean checks
    return ObserverCollectionSummary{
        .totalObservers = collectedObservers.size(),
        .containsDirectObserver = hasDirectObserver,
        .containsTransitiveObserver = hasTransitiveObserver
    };
}

